using System;class A{static void Main(){int N=int.Parse(Console.ReadLine());double[]X=new double[N],T=new double[N];for(int i=0;i<N;i++){var p=Console.ReadLine().Split(' ');X[i]=double.Parse(p[0]);T[i]=double.Parse(p[1]);}string[]nm={"O(1)","O(log n)","O(n)","O(n log n)","O(n^2)","O(n^2 log n)","O(n^3)","O(2^n)"};Func<double,double>[]fs={n=>1,Math.Log,n=>n,n=>n*Math.Log(n),n=>n*n,n=>n*n*Math.Log(n),n=>n*n*n,n=>Math.Pow(2,n)};double be=double.MaxValue;int bi=0;for(int k=0;k<8;k++){double xy=0,x2=0;bool ok=true;for(int i=0;i<N;i++){double v=fs[k](X[i]);if(double.IsInfinity(v)||double.IsNaN(v)){ok=false;break;}xy+=T[i]*v;x2+=v*v;}if(!ok||x2==0)continue;double c=xy/x2,e=0;for(int i=0;i<N;i++){double v=fs[k](X[i]),d=T[i]-c*v;e+=d*d;}if(e<be){be=e;bi=k;}}Console.Write(nm[bi]);}}